section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/product-development-trends.json",
  "title": "Product Development Trends",
  "type": "object",
  "required": [
    "artefact_id",
    "trends",
    "hype_curve",
    "adoption_signals",
    "applicability",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "trends": {
      "type": "array",
      "description": "\u22655 named trends",
      "minItems": 1
    },
    "hype_curve": {
      "type": "object",
      "description": "trend \u2192 {phase:peak|trough|slope, citation}"
    },
    "adoption_signals": {
      "type": "array",
      "description": "{trend, signal, source}",
      "minItems": 1
    },
    "applicability": {
      "type": "object",
      "description": "trend \u2192 fit_for_us assessment"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "product-development-trends-2026-05-23",
  "trends": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "hype_curve": {
    "key": "value"
  },
  "adoption_signals": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "applicability": {
    "key": "value"
  },
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
